class Solution {
    public long validSubstringCount(String word1, String word2) {
        int count = 0;
        int len1 = word1.length();
        int len2 = word2.length();

        for (int i = 0; i < len1; i++) {
            if (word2.length() > i && word2.charAt(i) == word1.charAt(i)) {
                count++;
                if (word2.length() > i + 1 && word2.charAt(i) == word1.charAt(i)) {
                    count++;
                }
            }
        }
        return count;
    }
}
